<?php
namespace App\Console\Commands;use App\Domain\Loot\LootGenerator;use App\Models\Monster;use Illuminate\Console\Command;
class GenerateMonsterLootCommand extends Command {protected $signature='game:loot:generate {monsterCode} {--times=1}';protected $description='Generate non-persistent monster loot';public function handle(LootGenerator $g){if(app()->environment('production')){$this->error('Unavailable in production.');return 1;}$times=filter_var($this->option('times'),FILTER_VALIDATE_INT);$m=Monster::where('code',$this->argument('monsterCode'))->where('status','active')->first();if(!$m||$times===false||$times<1||$times>100){$this->error('Invalid monster or times.');return 1;}$totals=[];for($n=1;$n<=$times;$n++){$r=$g->generateFor($m);$this->line("Simulation {$n} - Monster: {$r->monsterName()}");if(!$r->drops())$this->line('No items dropped.');foreach($r->drops() as $d){$this->line("- {$d->itemName()} x{$d->quantity()}");$totals[$d->itemName()]=($totals[$d->itemName()]??0)+$d->quantity();}}if($times>1){$this->line('Aggregated development simulation results:');foreach($totals as $name=>$quantity)$this->line("- {$name} x{$quantity}");}return 0;}}
